def format_options(options):
    formatted_options, formatted_alphabet = [], []
    for i, option in enumerate(options):
        formatted_alphabet.append(ALPHABET_LIST[i])
        formatted_options.append(f'{ALPHABET_LIST[i]}. {option}')
    return '\n'.join(formatted_options), ' or '.join(formatted_alphabet)


def run_llama(text, image, model, processor, max_new_tokens):
    messages = [
        {'role': 'user', 'content': [
            {'type': 'image'},
            {'type': 'text', 'text': text}
        ]}
    ]
    input_text = processor.apply_chat_template(messages, add_generation_prompt=True)
    inputs = processor(
        image,
        input_text,
        add_special_tokens=False,
        return_tensors='pt'
    ).to(model.device)
    output = model.generate(**inputs, max_new_tokens=max_new_tokens, temperature=0.001, top_p=0.9)
    output = processor.decode(output[0])
    return output
